## 0. Kotlin简介

### 0.1 简介

### 0.2 Kotlin安装

### 0.3 Hello, Kotlin

```kotlin
fun main(args:Array<String>)
{
    println("Hello, Kotlin!")
}
```

## 1. 类型和变量

### 1.1 变量声明(Variable Declarations)

```kotlin
fun main(args: Array<String>) {
    val_declarations()
}

fun val_declarations(){
    //val声明的变量不能更改
    val a:Int = 64
    val b:Long = 123

    //这种事不行的,必须每个占一行:
    //val c = 3, d = 4

    val c:Float = 3.4f //后面跟'F'或者'f'
    val d:Double = 3.4
    val e:Double = 12.3e5
    //不赋值的val声明
    val f: Int
    f = 13

    val g:StringBuffer = StringBuffer("test")
    g.replace(0, 1, "T")
    //打印
    println("$a $b $c $d $e $f")
    println("$g")

    //可更改的变量
    var h:Int = 123
    h = 45
    println("$h")
}
```

### 1.2 类型推导(Type Deduction)
类型能够根据赋值进行推到

```kotlin
fun main(args: Array<String>) {
    val_declarations()
}

fun val_declarations(){
    //val声明的变量不能更改
    val a = 64
    val b= 123
    val c = 3.4f //后面跟'F'或者'f'
    val d = 3.4
    val e = 12.3e5
    //不赋值的val声明，变量类型不能省略
    val f: Int
    f = 13

    val g = StringBuffer("test")
    g.replace(0, 1, "T")
    //打印
    println("$a $b $c $d $e $f")
    println("$g")

    //可更改的变量
    var h = 123
    h = 45
    println("$h")
}
```

### 1.3 Ranges

```kotlin
/**
 * Created by liulixiang on 16/2/26.
 */
fun main(args: Array<String>) {
    ranges()
}

fun ranges(){
    val a: IntRange = 1..10 //闭区间,而不是左闭右开. 1, 2, ..., 10(含10)
    //遍历range,使用in语法
    for (x in a) println(x)

    //除了上面的声明方式,还有以下声明方式:
    val b = 1.rangeTo(10)

    println("=====逆序=====")
    val c:IntProgression = b.reversed()
    for(x in c) println(x)

    println("=====range求和=====")
    println("sum of ints $c = ${c.sum()}")

    println("=====递减的range=====")
    val d = 10.downTo(1) //不能用10..1
    for(x in d) println(x)

    println("=====省略括号======")
    val e = 10 downTo 1
    for(x in e) println(x)

    println("=====根据变量声明range======")
    val m = 8
    val n = -3
    val f = IntRange(Math.min(m, n), Math.max(m, n))
    for(x in f) println(x)

    println("=====指定步长======")
    val g = 100 downTo 1 step 3
    for(x in g) print("$x\t")
    println()
}
```

### 1.4 数组


### 1.5 Strings and String Interpolation

```kotlin
fun main(args: Array<String>) {
    characters_and_strings()
}

fun characters_and_strings() {
    //字符
    println("=====字符=====")
    val a:Char = '\u0041'
    if (a.toInt() == 65){
        println("match")
    }

    //字符串
    println("=====字符=====")
    val b:String = "Hello"
    println(b)
    println("取字符串中的字符:${b[0]}")
    println("遍历字符串中的字符:")
    for(letter in b) print("$letter\t")
    println()

    //原始字符串
    println("=====原始字符串=====")
    val raw = """Hello
"test"
world"""
    println(raw)

    //字符串模板
    println("=====字符串模板=====")
    val c = 123.0
    val d = "c = $c, price = ${'$'}${c/10}"
    println(d)

    //range
    println("=====range=====")
    val e = "${(10 downTo 1).toList().map { it.toString().toList() }.joinToString()}"
    println(e)
}
```

## 2. 控制流

### 2.1 Nullability
在kotlin中`var x:String = null`是不允许的，因为它要求`x`不能为空。
```
fun main(args: Array<String>){}
```
对于上面的`args`表示的是由不能为空的`String`组成的不能为空的`Array`。

如果为null该怎么办，在类型名后添加`?`。

```kotlin
fun main(args: Array<String>) {
    nullability()
}

fun nullability(){
    var y:String? = null
    //下面的是错误的
    //println(y.length)
    var len: Int? = y?.length
    println(len)
    //或者这样返回-1，其中?:类似else，也就是说如果y是Null，就返回-1
    var len2:Int = y?.length ?: -1
    println(len2)

    //注意：1.系统库其实自动添加了null 检查，比如 System.out.println，其实是System?.out?.println
    //关闭null检查：y!!.length 如果此时y为null会抛出异常
}
```
### 2.2 If 语句

第一种是 `? :`形式
if语句直接返回值。

```kotlin
fun main(args: Array<String>) {
    if_statement()
}

fun if_statement() {
    //? :
    val temp = 20
